slayer={}

slayer["universal"]=write_feat("slayer-universal","Убийца чудовищ: Универсальный охотник",3,"icons/creatures/abilities/dragon-horned-blue.webp",
P("Когда вы объявляете существо своей Добычей, вы получаете особые преимущества в зависимости от вида существа. Эти преимущества длятся до конца боя или пока вы не объявите другое существо своей Добычей.")
+"<ul>"
+"<li><strong>Аберрация.</strong> Вы получаете Сопротивление урону Психической энергией. Также вы обладаете Иммунитетом к магии, позволяющей другим существам читать ваши мысли, и другие существа могут телепатически общаться с вами только если вы позволяете это.</li>"
+"<li><strong>Великан.</strong> Когда существо, которое больше вас как минимум на 1 категорию, совершает бросок атаки по вам, вы получаете бонус +2 к КД за каждую категорию. Например, если вы Среднего размера, вы получаете бонус +4 к КД против существ Огромного размера.</li>"
+"<li><strong>Дракон.</strong> Вы получаете Сопротивление урону, соответствующее виду дракона, и совершаете с Преимуществом спасброски от драконьего дыхания.</li>"
+"<li><strong>Зверь.</strong> Броски атак Зверей по вам не могут совершаться с Преимуществом, если у вас нет состояния Недееспособный. Также, один раз в ход, когда вы попадаете по Зверю рукопашной атакой, вы можете уменьшить его скорость вдвое до конца его следующего хода.</li>"
+"<li><strong>Исчадие.</strong> Вы получаете Сопротивление урону Огнём или Ядом (по вашему выбору) и совершаете спасброски, чтобы избежать или окончить на себе состояние Очарованный или Испуганный, с Преимуществом, если их источником было Исчадие.</li>"
+"<li><strong>Конструкт.</strong> Один раз в ход, когда вы причиняете урон своей Добыче, вы можете заставить цель совершить спасбросок Телосложения против СЛ ваших заклинаний. При провале цель не может использовать Реакции до конца своего следующего хода и на своём следующем ходу может совершить лишь что-то одно: передвигаться, совершить действие или совершить Бонусное действие.</li>"
+"<li><strong>Монстр.</strong> Вы можете выбрать любой другой эффект этого умения.</li>"
+"<li><strong>Небожитель.</strong> Вы получаете Сопротивление урону Излучением или Силовым полем (по вашему выбору) и совершаете с Преимуществом проверки характеристик и спасброски, чтобы избежать или окончить на себе состояние Ослепший, если его источником является Небожитель.</li>"
+"<li><strong>Нежить.</strong> Вы получаете Сопротивление урону Некротической энергией и один раз в ход, когда вы попадаете по Добыче атакой оружием, можете заменить вид урона от этой атаки на урон Излучением. Также вы совершаете с Преимуществом спасброски Телосложения, если их источником является Нежить.</li>"
+"<li><strong>Растение.</strong> Вы получаете Сопротивление урону Ядом и совершаете с Преимуществом проверки характеристик и спасброски, чтобы избежать или окончить на себе состояние Отравленный, Схваченный или Сбитый с ног.</li>"
+"<li><strong>Слизь.</strong> Вы получаете Сопротивление урону Кислотой, а также ваше снаряжение не получает повреждений от эффектов Слизи.</li>"
+"<li><strong>Фея.</strong> Вы получаете Сопротивление урону Психической энергией, и вас невозможно магически усыпить. Также вы совершаете с Преимуществом спасброски, чтобы избежать или окончить на себе состояние Очарованный, если его источником была Фея.</li>"
+"<li><strong>Элементаль.</strong> Вы получаете Сопротивление виду урона, соответствующему элементалю. Когда вы получаете этот эффект, вы можете также даровать другому согласному существу, которое можете видеть в пределах 15 футов, его слабый отголосок: каждый раз, когда выбранное существо получает соответствующий урон, оно может уменьшить его на значение вашего модификатора Мудрости.</li>"
+"</ul>")

slayer["awareness"]=write_feat("slayer-awareness","Убийца чудовищ: Сверхъестественная осведомленность",7,"icons/magic/perception/eye-tendrils-web-purple.webp",
P("Когда вы используете умение Первозданная осведомлённость, вы можете выбрать любой вид существ, кроме Гуманоидов.",
"Вы узнаёте направление, примерное расстояние до текущего местоположения существ и их количество. Если вы смогли ощутить присутствие группы существ, вы также узнаёте их усреднённый показатель опасности.",
"Начиная с 11-го уровня, помимо усреднённого показателя опасности вы можете также узнать наивысший показатель опасности среди обнаруженных существ."))

slayer["prep"]=write_feat("slayer-prep","Убийца чудовищ: Тщательная подготовка",7,"icons/consumables/potions/bottle-round-corked-green.webp",
P("Вы получаете владение набором травника. Всякий раз, заканчивая Долгий отдых, вы можете волшебным образом создать количество охотничьих отваров, равное вашему модификатору Мудрости, используя пустой сосуд, запасённые ингредиенты и подручные средства. При создании отвара выберите один из эффектов ниже. Бонусным действием существо может выпить отвар или влить его в согласное существо.",
"Вы можете действием создать дополнительный отвар, потратив ячейку заклинания 1-го уровня или выше за каждый отвар. Любой созданный отвар существует, пока не будет выпит, или до конца вашего следующего Долгого отдыха.")
+"<ul>"
+"<li><strong>Отвар звериной живучести.</strong> Выпивший получает 2d6 + ваш модификатор Мудрости временных хитов и совершает спасброски Телосложения с Преимуществом в течение 1 минуты. Количество временных хитов увеличивается на 2d6 на 11-м и 15-м уровнях.</li>"
+"<li><strong>Отвар незримого присутствия.</strong> Выпивший становится Невидимым на 1 минуту; эффект оканчивается, если он совершает атаку или накладывает заклинание. Длительность увеличивается на 30 минут на 11-м и 15-м уровнях. На 15-м уровне можно улучшить отвар, сократив действие до 2 раундов, — тогда эффект не оканчивается после атаки или заклинания.</li>"
+"<li><strong>Отвар стремительного передвижения.</strong> Скорость выпившего увеличивается на 10 футов на 1 минуту. На 11-м уровне бонус +10 футов, и Провоцированные атаки по нему совершаются с Помехой. На 15-м уровне бонус ещё +10 футов, и Труднопроходимая местность его не замедляет.</li>"
+"<li><strong>Отвар гномьей хитрости.</strong> Выпивший совершает спасброски Интеллекта, Мудрости или Харизмы с Преимуществом в течение 1 минуты. Можно выбрать дополнительный спасбросок на 11-м и 15-м уровнях.</li>"
+"<li><strong>Отвар сверхъестественных чувств.</strong> Выпивший получает Слепое зрение радиусом 30 футов на 1 минуту. Радиус увеличивается на 30 футов на 11-м и 15-м уровнях. На 15-м уровне можно улучшить отвар, сократив действие до 2 раундов, — тогда выпивший получает Истинное зрение радиусом 60 футов.</li>"
+"</ul>"
+"<p><em>Использований (создаваемых за Долгий отдых отваров): модификатор Мудрости (мин. 1); восстановление после Долгого отдыха. Владение набором травника выдаётся автоматически.</em></p>",
uses={"max":"max(1, @abilities.wis.mod)","period":"lr"},activation=("special",None),traits=["tool:herb"])

slayer["disrupt"]=write_feat("slayer-disrupt","Убийца чудовищ: Смещение чувств",11,"icons/magic/control/silhouette-hold-beam-blue.webp",
P("Вы получаете способность искажать чужую магию. Когда ваша Добыча накладывает заклинание или телепортируется, вы можете Реакцией заставить её совершить спасбросок Мудрости. При провале вы сами выбираете цель или область для заклинания либо точку для телепортации, как если бы вы были источником эффекта, однако вы используете бонус к попаданию и СЛ спасброска исходного существа.",
"Единожды перенаправив заклинание или телепортацию с помощью этого умения, вы не можете сделать это вновь, пока не завершите Долгий отдых. Вы также можете восстановить его использование, потратив ячейку заклинаний 3-го уровня.",
"<em>Использований: 1; восстановление после Долгого отдыха (либо за ячейку 3-го уровня — вручную).</em>"),
uses={"max":"1","period":"lr"},activation=("reaction",1))

slayer["pack"]=write_feat("slayer-pack","Убийца чудовищ: Стайный охотник",15,"icons/creatures/abilities/wolf-howl-moon-blue.webp",
P("Когда вы объявляете существо своей Добычей, вы можете также даровать преимущества от умения Универсальный охотник количеству существ, которых вы можете видеть в пределах 30 футов, равному вашему модификатору Мудрости."))

write_subclass("monster-slayer","Убийца чудовищ","icons/creatures/abilities/dragon-horned-blue.webp",
P("Вы посвятили себя охоте на существ ночи и обладателей мрачной магии. Убийца чудовищ ищет вампиров, драконов, злых фей, исчадий и другие магические угрозы, будучи экспертом в обнаружении и уничтожении могущественных мистических врагов."),
[A_spellgrant(3,[SLAYER_SPELLS[3]],"Заклинание (Защита от зла и добра)"),
 A_grant(3,[slayer["universal"]],"Универсальный охотник"),
 A_spellgrant(5,[SLAYER_SPELLS[5]],"Заклинание (Область истины)"),
 A_grant(7,[slayer["awareness"],slayer["prep"]],"Убийца чудовищ"),
 A_spellgrant(9,[SLAYER_SPELLS[9]],"Заклинание (Магический круг)"),
 A_grant(11,[slayer["disrupt"]],"Смещение чувств"),
 A_spellgrant(13,[SLAYER_SPELLS[13]],"Заклинание (Изгнание)"),
 A_grant(15,[slayer["pack"]],"Стайный охотник"),
 A_spellgrant(17,[SLAYER_SPELLS[17]],"Заклинание (Удержание чудовища)")])
print("Monster Slayer subclass + features written")
